item.content:encoded:
@font-face {
	font-family: 'Technor-Semibold';
	src: url('https://liskfence.com/technor-semibold/')
	format('woff2');
	font-weight: normal; 
	font-style: normal;
}

@font-face {
	font-family: 'switzer';
	src: url('https://liskfence.com/switzer-regular/')
	format('woff2');
	font-weight: normal; 
	font-style: normal;
}

h1, h2, h3, h4, h5, h6 {
	font-family: 'Technor-Semibold', sans-serif;
}

h1 {
	font-size: clamp(128px, 6.66vw, 256px);
	text-transform: uppercase;
}

h2 {
	font-size: clamp(36px, 3.33vw, 128px);
	text-transform: uppercase;
}

h5 {
	font-size: clamp(24px, 1.25vw, 48px);
	text-transform: uppercase;
}

h6 {
	font-size: clamp(20px, 1.05vw, 40px);
	text-transform: capitalize;
}

p {
	font-family: 'switzer', sans-serif;
	font-size: clamp(12px, 1.05vw, 40px);
}
